'use client';

import { useEffect } from 'react';
import Link from 'next/link';
import { AlertCircle, RefreshCcw, Home } from 'lucide-react';

export default function Error({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    // Log the error to an error reporting service
    console.error(error);
  }, [error]);

  return (
    <div className="flex flex-col flex-1 w-full min-h-[80vh] relative overflow-hidden bg-[#FAFAF7] items-center justify-center px-4">
      {/* Background Mandala / Aura effect */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-[#E8852A]/5 rounded-full blur-[100px] -z-10 pointer-events-none" />
      
      <div className="text-center space-y-8 animate-fade-in max-w-2xl">
        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-red-100 text-red-600 font-medium text-sm mb-4">
          <AlertCircle size={16} />
          <span>A Disturbance in the Energy</span>
        </div>
        
        <div className="space-y-4">
          <h1 className="text-4xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-[#2D5A3D]">
            Wisdom is <span className="text-[#E8852A] italic">Temporarily Obscured</span>
          </h1>
          <p className="text-lg text-[#8C8B84] max-w-md mx-auto text-body">
            An unexpected error has occurred while retrieving this knowledge. 
            The archive remains intact, but the connection was momentarily lost.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4 pt-4">
          <button
            onClick={() => reset()}
            className="w-full sm:w-auto px-8 py-4 bg-[#2D5A3D] text-white rounded-full font-medium hover:bg-[#1E3D29] transition-all flex items-center justify-center gap-2 shadow-lg"
          >
            <RefreshCcw size={18} /> Try Again
          </button>
          <Link 
            href="/" 
            className="w-full sm:w-auto px-8 py-4 bg-white text-[#2D5A3D] border border-[#2D5A3D]/20 rounded-full font-medium hover:bg-[#2D5A3D]/5 transition-all flex items-center justify-center gap-2"
          >
            <Home size={18} /> Return Home
          </Link>
        </div>
      </div>
    </div>
  );
}
